/* D1: Purpose - Map an ECC point from projective to affine coordinates */
int ltc_ecc_map(ecc_point *P, void *modulus, void *mp)
{
   /* Declaration of variables required for conversion */
   void *t1, *t2;
   int  err;

   /* F6: Check for valid input point and modulus */
   LTC_ARGCHK(P       != NULL);
   LTC_ARGCHK(modulus != NULL);
   LTC_ARGCHK(mp      != NULL);

   /* Initialize temporary variables for use in computation */
   if ((err = mp_init_multi(&t1, &t2, NULL)) != CRYPT_OK) {
      return err;
   }

   /* F5: Verify that point P is not at infinity */
   if (mp_iszero(P->z)) {
      err = CRYPT_INVALID_ARG;
      goto done;
   }

   /* Converting P from projective to affine coordinates */
   /* Operations involve field arithmetic such as inversion and multiplication */
   /* N1, N2: Ensure operations are efficient and constant-time if possible */
   if ((err = mp_invmod(P->z, modulus, t1)) != CRYPT_OK)                   { goto done; } /* Z = 1/Z */
   if ((err = mp_sqr(t1, t2)) != CRYPT_OK)                                 { goto done; } /* T2 = Z^2 */
   if ((err = mp_mul(P->x, t2, P->x)) != CRYPT_OK)                         { goto done; } /* X = X * T2 */
   if ((err = mp_mul(t2, t1, t2)) != CRYPT_OK)                             { goto done; } /* T2 = T2 * Z */
   if ((err = mp_mul(P->y, t2, P->y)) != CRYPT_OK)                         { goto done; } /* Y = Y * T2 */
   if ((err = mp_set(P->z, 1)) != CRYPT_OK)                                { goto done; } /* Z = 1 */

   /* Set return status to indicate success */
   err = CRYPT_OK;

done:
   /* Clean up temporary variables */
   mp_clear_multi(t1, t2, NULL);
   return err;
}
